730:     // Append literal character when possible. Then inclease the buffer_length.
731:     fn append_literal(self: *State, c: u8) void {
732:         // Only allow a-zA-Z.
733:         assert(std.ascii.isAlphabetic(c));
734: 
735:         // Check if we can add new span for input character.
736:         if (self.buffer_length < self.buffer_effective.len) {
737:             // Add character to span.
738:             self.buffer_effective[self.buffer_length] = Span.init(c);
739:         }
740:         // Increase the buffer length for tracking, we will need it went handling backspace.
741:         self.buffer_length += 1;
742: 
743:         // After increase, the new buffer_length may exceed the buffer_effective, set literal_index if needed.
744:         if (self.mode == .telex and self.literal_index == null and self.buffer_length == self.buffer_effective.len + 1) {
745:             self.literal_index = self.buffer_length - 1;
746:         }
747:     }
748: 
749:     // Return the last item in buffer_effective, not valid if the buffer_length is out of range.
750:     fn buffer_effective_last(self: *State) Span {
751:         // Should not work if buffer_length exceed buffer_effective.
752:         assert(self.buffer_length <= self.buffer_effective.len);
753: 
754:         return self.buffer_effective[self.buffer_length - 1];
755:     }
756: 
757:     fn backspace(self: *State) void {
758:         // buffer_length must be positive for backspace.
759:         assert(self.buffer_length > 0);
760: 
761:         // Input mode must be either .literal or .telex.
762:         assert(self.mode == .literal or self.mode == .telex);
763: 
764:         if (self.literal_index) |literal_index| {
765:             // Input mode must be .telex when literal_index is set.
766:             assert(self.mode == .telex);
767:             // literal_index must be within buffer range when set.
768:             assert(literal_index < self.buffer_length);
769:         }
770: 
771:         // decrease the buffer_length to match the backspace.
772:         self.buffer_length -= 1;
773:         // because backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
774:         self.buffer_modification_index = null;
775:         // if the literal_index is out of buffer range, unset it.
776:         if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
777:             self.literal_index = null;
778:         }
779:     }
780: };
