1696:     }
1697: 
1698:     // Assert
1699:     // We only fill and increase the buffer_length based on input.
1700:     try expectEqual(10, state.buffer_length);
1701:     // Because we don't modify any existing character since the last input, expect null.
1702:     try expectEqual(null, state.buffer_modification_index);
1703:     // Because we didn't exceed the buffer_affective, don't set literal_index.
1704:     try expectEqual(null, state.literal_index);
1705:     // Don't touch on input mode.
1706:     try expectEqual(.telex, state.mode);
1707:     // Verify every the spans, must exactly the same with the input.
1708:     for (input_sequence, 0..) |c, i| {
1709:         const sp = state.buffer_effective[i];
1710:         try expectEqual(c, sp.base);
1711:         try expectEqual(.empty, sp.diacritic);
1712:         try expectEqual(.level, sp.tone);
1713:     }
1714: }
1715: 
1716: // Add operations to the given state based on Telex rules, operations are determined by the input
1717: // character.
1718: export fn lex_add(state: *anyopaque, c: u8) void {
1719:     const s: *State = @ptrCast(@alignCast(state));
1720:     s.add(c);
1721: }
1722: 
1723: export fn lex_backspace(state: *anyopaque) void {
1724:     const s: *State = @ptrCast(@alignCast(state));
1725:     s.backspace();
1726: }
